INSERT INTO FACE_RECG_TBL (
	 TRAD_DATE
	,USER_CIF_NO
	,FACE_TRANSACTION_ID
	,CUST_NO
	,TRAD_NO
	,FACE_RECG_YN
	,FACE_RECG_SCORE
	,FACE_RECG_CD
	,FACE_RECG_MSG
	,FACE_RECG_DATE

	,SELFIE_PATH


	,FILE_PATH


	,FILE_NAME

	,REGISTER_DATE
) VALUES (
	 VARCHAR_FORMAT(CURRENT TIMESTAMP, 'YYYYMMDD')
	,#{userCifNo}
	,#{faceTransactionId}
	,#{custNo}
	,#{tradNo}
	,#{faceRecgYn}
	,#{faceRecgScore}
	,#{faceRecgCd}
	,#{faceRecgMsg}
	,#{faceRecgData}

	,#{selfiePath}


	,#{filePath}


	,#{fileName}

	,CURRENT TIMESTAMP
)
